function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === "object");
}

function extractData<T>(payload: unknown): T | undefined {
  if (!isRecord(payload)) return payload as T;
  if (payload.data !== undefined) return payload.data as T;
  return payload as T;
}

function extractPage<T>(payload: unknown): PageResult<T> {
  const root = isRecord(payload) ? payload : {};
  const data = isRecord(root.data) ? root.data : root;
  const rows = Array.isArray(data.rows)
    ? data.rows
    : Array.isArray(root.rows)
      ? root.rows
      : Array.isArray(data)
        ? data
        : [];
  const meta = (
    isRecord(data.meta)
      ? data.meta
      : isRecord(root.meta)
        ? root.meta
        : undefined
  ) as PageMeta | undefined;
  return { rows: rows as T[], meta };
}

function endpoint(path: string, params?: Record<string, unknown>) {
  return `${path}${buildQueryString(params)}`;
}

async function adminGet<T>(path: string, params?: Record<string, unknown>) {
  return signedAdminRequest<T>({ endpoint: endpoint(path, params) });
}

async function adminPost<T>(path: string, data: Record<string, unknown>) {
  return signedAdminRequest<T>({ endpoint: path, method: "POST", data });
}

async function publicGet<T>(path: string, params?: Record<string, unknown>) {
  return orderlyApi<T>({ endpoint: endpoint(path, params), token: null });
}

function errorMessage(error: unknown, fallback: string) {
  if (error instanceof Error && error.message) return error.message;
  if (typeof error === "string" && error) return error;
  if (isRecord(error) && typeof error.message === "string")
    return error.message;
  return fallback;
}

function numberValue(value: unknown, fallback = 0) {
  const numeric =
    typeof value === "number"
      ? value
      : typeof value === "string"
        ? Number(value)
        : NaN;
  return Number.isFinite(numeric) ? numeric : fallback;
}

function formatCompactNumber(
  value: unknown,
  options: Intl.NumberFormatOptions = {}
) {
  return numberValue(value).toLocaleString(undefined, options);
}

function formatCurrency(value: unknown) {
  return `$${formatCompactNumber(value, { maximumFractionDigits: 0 })}`;
}

function formatPercent(value?: number | null) {
  if (value === null || value === undefined || !Number.isFinite(value))
    return "--";
  const percent = value * 100;
  const formatted = Number.isInteger(percent)
    ? percent.toString()
    : percent
        .toFixed(2)
        .replace(/\.00$/, "")
        .replace(/(\.\d)0$/, "$1");
  return `${formatted}%`;
}

function formatPercentNumber(value: number) {
  return `${Math.round(value)}%`;
}

function rateToPercent(value?: number | null) {
  if (value === null || value === undefined || !Number.isFinite(value))
    return 0;
  return Math.round(Math.max(0, value) * 100);
}

function getBaseReferralRate(config?: MLRConfig | null) {
  return config?.base_rebate_rate ?? config?.direct_bonus_rebate_rate ?? 0;
}

function getBonusReferralRate(config?: MLRConfig | null) {
  return config?.bonus_max_rebate_rate ?? config?.max_rebate_rate ?? 0;
}

function getDexEarningsPercent(basePercent: number, bonusPercent: number) {
  return Math.max(0, 100 - basePercent - bonusPercent).toString();
}

function getAffiliateGetsPercent(
  affiliate?: AffiliateRow,
  config?: MLRConfig | null
) {
  if (
    affiliate?.bonus_max_rebate_rate !== undefined ||
    affiliate?.base_rebate_rate !== undefined
  ) {
    return rateToPercent(
      (affiliate.bonus_max_rebate_rate ?? 0) + (affiliate.base_rebate_rate ?? 0)
    );
  }
  if (
    affiliate?.max_rebate_rate !== undefined ||
    affiliate?.direct_bonus_rebate_rate !== undefined
  ) {
    return rateToPercent(
      (affiliate.max_rebate_rate ?? 0) +
        (affiliate.direct_bonus_rebate_rate ?? 0)
    );
  }
  return rateToPercent(
    getBonusReferralRate(config) + getBaseReferralRate(config)
  );
}

function getBaseRebatePercent(
  affiliate?: AffiliateRow,
  config?: MLRConfig | null
) {
  if (affiliate?.base_rebate_rate !== undefined)
    return rateToPercent(affiliate.base_rebate_rate);
  if (affiliate?.direct_bonus_rebate_rate !== undefined)
    return rateToPercent(affiliate.direct_bonus_rebate_rate);
  return rateToPercent(getBaseReferralRate(config));
}

function sanitizePercentInput(value: string, maxValue: number) {
  const digits = value.replace(/[^0-9]/g, "");
  if (digits === "") return "";
  const numericValue = Number(digits);
  if (!Number.isFinite(numericValue)) return "0";
  return String(Math.min(maxValue, Math.max(0, numericValue)));
}

function formatShort(value?: string | null, start = 8, end = 6) {
  if (!value) return "--";
  if (value.length <= start + end + 3) return value;
  return `${value.slice(0, start)}...${value.slice(-end)}`;
}

function formatDate(value?: number | string | null) {
  if (value === undefined || value === null || value === "") return "--";
  const numeric =
    typeof value === "number"
      ? value
      : /^\d+$/.test(value)
        ? Number(value)
        : NaN;
  const timestamp = Number.isFinite(numeric)
    ? numeric < 10_000_000_000
      ? numeric * 1000
      : numeric
    : Date.parse(String(value));
  if (!Number.isFinite(timestamp)) return String(value);
  return new Date(timestamp).toLocaleString();
}

function getTotal(meta?: PageMeta, fallbackLength = 0) {
  return Number(meta?.total || fallbackLength || 0);
}

function getChainType(address: string) {
  return /^[1-9A-HJ-NP-Za-km-z]{32,44}$/.test(address.trim()) ? "SOL" : "EVM";
}

function normalizeReferralCode(value: string) {
  return value.replace(/[^A-Z0-9]/g, "").toUpperCase();
}

function referralCodeError(value: string, t: (key: string) => string) {
  if (!value) return t("affiliate.error.referralCodeRequired");
  if (value.length < 4 || value.length > 10) {
    return t("affiliate.error.referralCodeLength");
  }
  return "";
}

function getBrokerContext(fallbackBrokerName = "your DEX") {
  if (typeof window === "undefined")
    return { brokerId: "", brokerName: fallbackBrokerName };
  const sources = ["orderlyProfile", "orderlyLoginContext", "orderlyApiKey"];
  for (const suffix of sources) {
    const raw = walletGetItem(suffix);
    if (!raw) continue;
    try {
      const parsed = JSON.parse(raw) as {
        brokerId?: string;
        brokerName?: string;
        builderName?: string;
      };
      if (parsed.brokerId) {
        return {
          brokerId: parsed.brokerId,
          brokerName:
            parsed.brokerName || parsed.builderName || parsed.brokerId,
        };
      }
    } catch {
      // Ignore malformed local storage values.
    }
  }
  return { brokerId: "", brokerName: fallbackBrokerName };
}

