function CopyableIdentifier({
  value,
  label,
  start = 8,
  end = 6,
}: {
  value?: string | null;
  label: string;
  start?: number;
  end?: number;
}) {
  const { t } = useTranslation();
  const [copied, setCopied] = useState(false);

  if (!value) return <span>--</span>;

  async function copyValue(event: React.MouseEvent<HTMLButtonElement>) {
    event.stopPropagation();
    try {
      await navigator.clipboard.writeText(value || "");
      setCopied(true);
      toast({ title: t("affiliate.copySuccess", { label }) });
      window.setTimeout(() => setCopied(false), 1400);
    } catch {
      setCopied(false);
      toast({
        title: t("affiliate.copyFailed", { label }),
        variant: "destructive",
      });
    }
  }

  return (
    <span className="inline-flex max-w-full items-center gap-1.5 align-middle">
      <span className="truncate font-mono" title={value}>
        {formatShort(value, start, end)}
      </span>
      <button
        type="button"
        onClick={copyValue}
        aria-label={
          copied
            ? t("affiliate.copiedLabel", { label })
            : t("affiliate.copyLabel", { label })
        }
        className={`inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-md transition-colors ${copied ? "text-[#1DF6B5]" : "text-(--fg-tertiary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"}`}
      >
        {copied ? (
          <Check className="h-3.5 w-3.5" />
        ) : (
          <Copy className="h-3.5 w-3.5" />
        )}
      </button>
    </span>
  );
}

