function EnableMLRModal({
  open,
  hasLegacyReferralProgram,
  onClose,
  onSuccess,
}: {
  open: boolean;
  hasLegacyReferralProgram: boolean;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t } = useTranslation();
  const [commissionRate, setCommissionRate] = useState(() =>
    String(DEFAULT_ENABLE_CONFIG.base_rebate_rate * 100)
  );
  const [legacyChecked, setLegacyChecked] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const commissionPercent = Math.min(
    100,
    Math.max(0, Number(commissionRate) || 0)
  );
  const dexEarnings = Math.max(0, 100 - commissionPercent);

  useEffect(() => {
    if (!open) return;
    setCommissionRate(String(DEFAULT_ENABLE_CONFIG.base_rebate_rate * 100));
    setLegacyChecked(false);
    setError("");
  }, [open]);

  async function submit() {
    if (hasLegacyReferralProgram && !legacyChecked) {
      setError(t("affiliate.error.confirmPermanentUpgrade"));
      return;
    }
    setSubmitting(true);
    setError("");
    try {
      await adminPost("/v1/referral/multi_level/admin", {
        enable: true,
        default_rebate_rate: DEFAULT_ENABLE_CONFIG.default_rebate_rate,
        base_rebate_rate: commissionPercent / 100,
        required_volume: DEFAULT_ENABLE_CONFIG.required_volume,
      });
      toast({ title: t("affiliate.mlrEnabled") });
      onSuccess();
      onClose();
    } catch (err) {
      setError(errorMessage(err, t("affiliate.error.enableMlr")));
    } finally {
      setSubmitting(false);
    }
  }

  const title = hasLegacyReferralProgram
    ? t("affiliate.upgradeMlrQuestion")
    : t("affiliate.enableMlrTitle");
  const okText = hasLegacyReferralProgram
    ? t("affiliate.upgrade")
    : t("affiliate.enable");

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={title}
      className="max-w-[560px]"
    >
      <div className="space-y-4">
        <p className="text-sm leading-6 text-(--fg-secondary)">
          {t("affiliate.enableMlrRevenueSplitDesc")}
        </p>
        <div className="grid gap-3 sm:grid-cols-2">
          <MetricCard
            label={t("affiliate.dexEarnings")}
            value={formatPercentNumber(dexEarnings)}
          />
          <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
            <label
              htmlFor="enable-base-rate"
              className="text-sm font-medium text-(--fg-primary)"
            >
              {t("affiliate.baseReferralAllocation")}
            </label>
            <div className="mt-3 flex items-center gap-2">
              <Input
                id="enable-base-rate"
                value={commissionRate}
                onChange={event =>
                  setCommissionRate(event.target.value.replace(/[^0-9]/g, ""))
                }
                className={fieldClassName("text-right")}
              />
              <span className="text-sm text-(--fg-secondary)">%</span>
            </div>
            <p className="mt-2 text-xs leading-5 text-(--fg-secondary)">
              {t("affiliate.baseReferralAllocationDesc")}
            </p>
          </div>
        </div>
        {hasLegacyReferralProgram && (
          <div className="rounded-xl border border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)] p-3 text-sm leading-6 text-[#D9AB52]">
            <p>{t("affiliate.upgradePermanentWithLegacy")}</p>
            <label className="mt-3 flex items-start gap-2 text-xs leading-5">
              <OdsCheckbox
                checked={legacyChecked}
                onCheckedChange={checked => setLegacyChecked(checked === true)}
                className="mt-1"
              />
              {t("affiliate.confirmPermanentUpgrade")}
            </label>
          </div>
        )}
        <ErrorBanner message={error} />
        <ConfirmFooter
          okText={okText}
          onCancel={onClose}
          onConfirm={submit}
          disabled={commissionPercent > 100 || commissionPercent < 0}
          loading={submitting}
        />
      </div>
    </Modal>
  );
}

function MLRSettingsModal({
  open,
  mode,
  config,
  onClose,
  onSuccess,
}: {
  open: boolean;
  mode: "commission" | "volume";
  config: MLRConfig | null;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t } = useTranslation();
  const [value, setValue] = useState("0");
  const [dexEarningsRate, setDexEarningsRate] = useState("0");
  const [baseCommissionRate, setBaseCommissionRate] = useState("0");
  const [bonusCommissionRate, setBonusCommissionRate] = useState("0");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const isCommission = mode === "commission";
  const baseCommissionPercent = Number(baseCommissionRate) || 0;
  const bonusCommissionPercent = Number(bonusCommissionRate) || 0;
  const hasBonusCommission = getBonusReferralRate(config) > 0;
  const activeBonusPercent = hasBonusCommission ? bonusCommissionPercent : 0;
  const numericValue = Number(value) || 0;
  const earningsTotal =
    (Number(dexEarningsRate) || 0) + baseCommissionPercent + activeBonusPercent;
  const earningsTotalError =
    isCommission && earningsTotal !== 100
      ? "The total of all fields must equal 100%."
      : "";

  useEffect(() => {
    if (!open) return;
    setError("");
    if (mode === "commission") {
      const nextBasePercent = Math.round(getBaseReferralRate(config) * 100);
      const nextBonusPercent = Math.round(getBonusReferralRate(config) * 100);
      setBaseCommissionRate(String(nextBasePercent));
      setBonusCommissionRate(String(nextBonusPercent));
      setDexEarningsRate(
        getDexEarningsPercent(nextBasePercent, nextBonusPercent)
      );
      return;
    }
    setValue(String(Math.ceil(config?.required_volume ?? 0)));
  }, [config, mode, open]);

  function handleBaseCommissionRateChange(inputValue: string) {
    const nextBaseRate = sanitizePercentInput(
      inputValue,
      Math.max(0, 100 - activeBonusPercent)
    );
    setBaseCommissionRate(nextBaseRate);
    if (nextBaseRate === "") return;
    setDexEarningsRate(
      getDexEarningsPercent(Number(nextBaseRate) || 0, activeBonusPercent)
    );
  }

  function handleDexEarningsRateChange(inputValue: string) {
    const nextDexEarningsRate = sanitizePercentInput(
      inputValue,
      hasBonusCommission ? Math.max(0, 100 - baseCommissionPercent) : 100
    );
    setDexEarningsRate(nextDexEarningsRate);
    if (nextDexEarningsRate === "") return;

    const nextDexEarningsPercent = Number(nextDexEarningsRate) || 0;
    if (hasBonusCommission) {
      setBonusCommissionRate(
        String(
          Math.max(0, 100 - nextDexEarningsPercent - baseCommissionPercent)
        )
      );
      return;
    }
    setBaseCommissionRate(String(Math.max(0, 100 - nextDexEarningsPercent)));
  }

  function handleBonusCommissionRateChange(inputValue: string) {
    const nextBonusRate = sanitizePercentInput(
      inputValue,
      Math.max(0, 100 - baseCommissionPercent)
    );
    setBonusCommissionRate(nextBonusRate);
    if (nextBonusRate === "") return;
    setDexEarningsRate(
      getDexEarningsPercent(baseCommissionPercent, Number(nextBonusRate) || 0)
    );
  }

  function handleBaseCommissionRateBlur() {
    if (baseCommissionRate !== "") return;
    setBaseCommissionRate("0");
    setDexEarningsRate(getDexEarningsPercent(0, activeBonusPercent));
  }

  function handleDexEarningsRateBlur() {
    if (dexEarningsRate !== "") return;
    setDexEarningsRate("0");
    if (hasBonusCommission) {
      setBonusCommissionRate(String(Math.max(0, 100 - baseCommissionPercent)));
      return;
    }
    setBaseCommissionRate("100");
  }

  function handleBonusCommissionRateBlur() {
    if (bonusCommissionRate !== "") return;
    setBonusCommissionRate("0");
    setDexEarningsRate(getDexEarningsPercent(baseCommissionPercent, 0));
  }

  async function submit() {
    setSubmitting(true);
    setError("");
    try {
      if (mode === "commission") {
        await adminPost("/v1/referral/multi_level/admin/update", {
          required_volume: config?.required_volume ?? 0,
          default_rebate_rate: activeBonusPercent / 100,
          base_rebate_rate: baseCommissionPercent / 100,
        });
        toast({ title: t("affiliate.referralAllocationSaved") });
      } else {
        await adminPost("/v1/referral/multi_level/admin/update", {
          required_volume: Math.max(0, numericValue),
          default_rebate_rate: getBonusReferralRate(config),
          base_rebate_rate: getBaseReferralRate(config),
        });
        toast({ title: t("affiliate.volumeRequirementSaved") });
      }
      onSuccess();
      onClose();
    } catch (err) {
      setError(errorMessage(err, t("affiliate.error.saveSettings")));
    } finally {
      setSubmitting(false);
    }
  }

  const title = isCommission
    ? t("affiliate.editEarningsSettings")
    : t("affiliate.editEligibilitySettings");

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={title}
      className="max-w-[640px]"
    >
      <div className="space-y-4">
        {isCommission ? (
          <>
            <p className="text-sm leading-6 text-(--fg-secondary)">
              {hasBonusCommission
                ? t("affiliate.editEarningsRevenueSplitDesc")
                : t("affiliate.enableMlrRevenueSplitDesc")}
            </p>
            <div className="space-y-3">
              <PercentInputCard
                id="mlr-dex-earnings-rate"
                label={t("affiliate.dexEarnings")}
                value={dexEarningsRate}
                onBlur={handleDexEarningsRateBlur}
                onChange={handleDexEarningsRateChange}
              />
              <PercentInputCard
                id="mlr-base-commission-rate"
                label={t("affiliate.baseReferralAllocation")}
                value={baseCommissionRate}
                description={t("affiliate.baseReferralAllocationDesc")}
                onBlur={handleBaseCommissionRateBlur}
                onChange={handleBaseCommissionRateChange}
              />
              {hasBonusCommission && (
                <PercentInputCard
                  id="mlr-bonus-commission-rate"
                  label={t("affiliate.multilevelAllocation")}
                  value={bonusCommissionRate}
                  description={t("affiliate.multilevelReferralAllocationDesc")}
                  onBlur={handleBonusCommissionRateBlur}
                  onChange={handleBonusCommissionRateChange}
                />
              )}
            </div>
            {earningsTotalError && (
              <p className="text-xs font-medium text-(--fg-negative)">
                {earningsTotalError}
              </p>
            )}
          </>
        ) : (
          <div className="space-y-5">
            <div>
              <p className="text-sm font-medium text-(--fg-primary)">
                {t("affiliate.referralCodeEligibility")}
              </p>
              <p className="mt-1 text-sm leading-6 text-(--fg-secondary)">
                {t("affiliate.referralCodeEligibilityDesc")}
              </p>
            </div>
            <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
              <OdsInput
                id="mlr-volume"
                label={t("affiliate.minimumTradingVolume")}
                value={value}
                inputMode="numeric"
                onChange={event =>
                  setValue(event.target.value.replace(/[^0-9]/g, ""))
                }
                suffix="USDC"
                className="h-11"
                inputClassName="text-right"
                message={
                  numericValue === 0
                    ? t("affiliate.zeroVolumeMeansAllUsers")
                    : t("affiliate.usersNeedMinimumVolume", {
                        amount: formatCompactNumber(numericValue, {
                          maximumFractionDigits: 0,
                        }),
                      })
                }
              />
            </div>
          </div>
        )}
        <ErrorBanner message={error} />
        <ConfirmFooter
          okText={t("common.save")}
          onCancel={onClose}
          onConfirm={submit}
          disabled={Boolean(earningsTotalError)}
          loading={submitting}
        />
      </div>
    </Modal>
  );
}

function AllocationRange({
  value,
  onChange,
  disabled,
  directBonusPercent = 0,
}: {
  value: number;
  onChange: (value: number) => void;
  disabled?: boolean;
  directBonusPercent?: number;
}) {
  const { t } = useTranslation();
  const affiliateGets = 100 - value;
  const clampedValue = Math.max(0, Math.min(100, value));
  const clampedDirectBonusPercent = Math.max(
    0,
    Math.min(100, directBonusPercent)
  );
  const stripedBonusStyle = {
    backgroundColor: "#1D1A26",
    backgroundImage:
      "repeating-linear-gradient(135deg, rgba(255,255,255,0.14) 0 4px, rgba(255,255,255,0.03) 4px 8px)",
  };

  return (
    <div className="space-y-3">
      <div className={`relative h-8 ${disabled ? "opacity-60" : ""}`}>
        <div className="absolute left-0 right-0 top-1/2 h-2 -translate-y-1/2 overflow-hidden rounded-full border border-(--line-subtle) bg-(--bg-input)">
          <div
            className="absolute left-0 top-0 h-full bg-[#00B59F]"
            style={{ width: `${clampedValue}%` }}
          />
          {clampedDirectBonusPercent > 0 && (
            <div
              className="absolute right-0 top-0 h-full"
              style={{
                ...stripedBonusStyle,
                width: `${clampedDirectBonusPercent}%`,
              }}
            />
          )}
        </div>
        <div
          className="pointer-events-none absolute top-1/2 h-4 w-4 -translate-x-1/2 -translate-y-1/2 rounded-full bg-(--fg-primary) shadow-[0_0_0_3px_rgba(9,6,16,0.75)]"
          style={{ left: `${clampedValue}%` }}
        />
        <input
          type="range"
          min={0}
          max={100}
          step={1}
          value={value}
          onChange={event => onChange(Number(event.target.value))}
          disabled={disabled}
          aria-label={t("affiliate.referralAllocationSplit")}
          className="absolute inset-x-0 top-1/2 h-8 -translate-y-1/2 cursor-pointer opacity-0 disabled:cursor-not-allowed"
        />
      </div>
      <div className="flex items-center justify-between gap-3 text-sm">
        <div>
          <div className="text-xs text-(--fg-secondary)">
            {t("affiliate.youKeep")}
          </div>
          <div className="text-lg font-semibold text-[#00B59F]">
            {formatPercentNumber(value)}
          </div>
        </div>
        <div className="text-right">
          <div className="text-xs text-(--fg-secondary)">
            {t("affiliate.affiliateGets")}
          </div>
          <div className="text-lg font-semibold text-(--fg-primary)">
            {formatPercentNumber(affiliateGets)}
          </div>
        </div>
      </div>
      {clampedDirectBonusPercent > 0 && (
        <div className="flex items-center gap-2 text-xs leading-5 text-(--fg-secondary)">
          <span
            className="h-3 w-6 shrink-0 rounded-sm border border-(--line-subtle)"
            style={stripedBonusStyle}
          />
          <span>
            {t("affiliate.directBonusAllocationDesc", {
              percent: formatPercentNumber(clampedDirectBonusPercent),
            })}
          </span>
        </div>
      )}
    </div>
  );
}

function CreateAffiliateCodeModal({
  open,
  config,
  onClose,
  onSuccess,
}: {
  open: boolean;
  config: MLRConfig | null;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t } = useTranslation();
  const brokerContext = useMemo(
    () => getBrokerContext(t("affiliate.yourDex")),
    [open, t]
  );
  const [affiliateAddress, setAffiliateAddress] = useState("");
  const [accountId, setAccountId] = useState("");
  const [referralCode, setReferralCode] = useState("");
  const [addressError, setAddressError] = useState("");
  const [codeError, setCodeError] = useState("");
  const [checkingAccount, setCheckingAccount] = useState(false);
  const [checkingCode, setCheckingCode] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState("");
  const bonusPercent = Math.floor(getBaseReferralRate(config) * 100);
  const defaultMaxRebatePercent = Math.floor(
    getBonusReferralRate(config) * 100
  );
  const maxYouKeep = Math.max(0, 100 - bonusPercent);
  const [youKeep, setYouKeep] = useState(
    Math.max(0, 100 - bonusPercent - defaultMaxRebatePercent)
  );
  const maxRebatePercent = Math.max(0, 100 - youKeep - bonusPercent);

  useEffect(() => {
    if (!open) return;
    setAffiliateAddress("");
    setAccountId("");
    setReferralCode("");
    setAddressError("");
    setCodeError("");
    setSubmitError("");
    setYouKeep(Math.max(0, 100 - bonusPercent - defaultMaxRebatePercent));
  }, [bonusPercent, defaultMaxRebatePercent, open]);

  useEffect(() => {
    if (!open || !affiliateAddress.trim()) return;
    if (!brokerContext.brokerId) {
      setAddressError(t("affiliate.error.brokerIdMissing"));
      return;
    }
    let cancelled = false;
    const timeout = window.setTimeout(async () => {
      setCheckingAccount(true);
      setAddressError("");
      setAccountId("");
      try {
        const payload = await adminGet<AccountLookupResponse>(
          "/v1/get_account",
          {
            address: affiliateAddress.trim(),
            broker_id: brokerContext.brokerId,
            chain_type: getChainType(affiliateAddress),
          }
        );
        if (cancelled) return;
        const response = extractData<AccountLookupResponse>(payload) || payload;
        const resolvedAccountId =
          response.data?.account_id ||
          (isRecord(response) && typeof response.account_id === "string"
            ? response.account_id
            : "");
        if (response.success === false || !resolvedAccountId) {
          setAddressError(
            response.message ||
              t("affiliate.error.addressNotRegistered", {
                brokerName: brokerContext.brokerName,
              })
          );
          return;
        }
        setAccountId(resolvedAccountId);
      } catch {
        if (!cancelled)
          setAddressError(
            t("affiliate.error.addressNotRegistered", {
              brokerName: brokerContext.brokerName,
            })
          );
      } finally {
        if (!cancelled) setCheckingAccount(false);
      }
    }, 350);
    return () => {
      cancelled = true;
      window.clearTimeout(timeout);
    };
  }, [
    affiliateAddress,
    brokerContext.brokerId,
    brokerContext.brokerName,
    open,
    t,
  ]);

  useEffect(() => {
    if (!open || !referralCode) return;
    const localError = referralCodeError(referralCode, t);
    if (localError) {
      setCodeError(localError);
      return;
    }
    let cancelled = false;
    const timeout = window.setTimeout(async () => {
      setCheckingCode(true);
      try {
        const payload = await publicGet<VerifyReferralCodeResponse>(
          "/v1/public/referral/verify_ref_code",
          { referral_code: referralCode }
        );
        if (cancelled) return;
        const response =
          extractData<VerifyReferralCodeResponse>(payload) || payload;
        setCodeError(
          response.data?.exist ? t("affiliate.error.codeExists") : ""
        );
      } catch {
        if (!cancelled) setCodeError("");
      } finally {
        if (!cancelled) setCheckingCode(false);
      }
    }, 350);
    return () => {
      cancelled = true;
      window.clearTimeout(timeout);
    };
  }, [open, referralCode, t]);

  async function submit() {
    setSubmitError("");
    if (!accountId) {
      setAddressError(
        t("affiliate.error.addressNotRegistered", {
          brokerName: brokerContext.brokerName,
        })
      );
      return;
    }
    const localCodeError = referralCodeError(referralCode, t);
    if (localCodeError) {
      setCodeError(localCodeError);
      return;
    }
    setSubmitting(true);
    try {
      await adminPost("/v1/referral/multi_level/admin/create/affiliate", {
        account_id: accountId,
        referral_code: referralCode,
        max_rebate_rate: maxRebatePercent / 100,
      });
      toast({ title: t("affiliate.l1CodeCreated") });
      onSuccess();
      onClose();
    } catch (err) {
      let message = errorMessage(err, t("affiliate.error.createReferralCode"));
      if (message === "referral code existed")
        message = t("affiliate.error.duplicateCodes");
      setSubmitError(message);
    } finally {
      setSubmitting(false);
    }
  }

  const disabled =
    submitting ||
    checkingAccount ||
    checkingCode ||
    !accountId ||
    !affiliateAddress.trim() ||
    !referralCode ||
    Boolean(addressError || codeError);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={t("affiliate.createReferralCode")}
      className="max-w-[560px]"
    >
      <div className="space-y-4">
        <div className="rounded-xl border border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)] px-3 py-2 text-sm text-[#D9AB52]">
          {t("affiliate.l1OnlyCreateCode")}
        </div>
        <div>
          <label
            htmlFor="affiliate-address"
            className="text-sm font-medium text-(--fg-primary)"
          >
            {t("affiliate.affiliateAddress")}
          </label>
          <div className="mt-2">
            <OdsInput
              id="affiliate-address"
              value={affiliateAddress}
              onChange={event => setAffiliateAddress(event.target.value)}
              placeholder={t("affiliate.addressPlaceholder")}
              action={
                checkingAccount ? (
                  <Loader2 className="h-4 w-4 animate-spin text-(--fg-secondary)" />
                ) : null
              }
            />
          </div>
          {addressError && (
            <p className="mt-1 text-xs text-(--fg-negative)">{addressError}</p>
          )}
        </div>
        <div>
          <label
            htmlFor="referral-code"
            className="text-sm font-medium text-(--fg-primary)"
          >
            {t("affiliate.referralCode")}
          </label>
          <div className="mt-2">
            <OdsInput
              id="referral-code"
              value={referralCode}
              onChange={event =>
                setReferralCode(normalizeReferralCode(event.target.value))
              }
              inputClassName="uppercase"
              placeholder="ABCD1234"
              action={
                checkingCode ? (
                  <Loader2 className="h-4 w-4 animate-spin text-(--fg-secondary)" />
                ) : null
              }
            />
          </div>
          {codeError && (
            <p className="mt-1 text-xs text-(--fg-negative)">{codeError}</p>
          )}
        </div>
        <AllocationRange
          value={youKeep}
          onChange={value => setYouKeep(Math.min(value, maxYouKeep))}
          directBonusPercent={bonusPercent}
        />
        <ErrorBanner message={submitError} />
        <ConfirmFooter
          okText={t("common.create")}
          onCancel={onClose}
          onConfirm={submit}
          disabled={disabled}
          loading={submitting}
        />
      </div>
    </Modal>
  );
}

function EditAffiliateModal({
  open,
  affiliate,
  config,
  onClose,
  onSuccess,
}: {
  open: boolean;
  affiliate?: AffiliateRow;
  config: MLRConfig | null;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t } = useTranslation();
  const [youKeep, setYouKeep] = useState(50);
  const [initialYouKeep, setInitialYouKeep] = useState(50);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const baseRebatePercent = getBaseRebatePercent(affiliate, config);
  const maxYouKeep = Math.max(0, 100 - baseRebatePercent);
  const bonusMaxRebatePercent = Math.max(0, 100 - youKeep - baseRebatePercent);

  useEffect(() => {
    if (!open || !affiliate) return;
    const affiliateGetsPercent = getAffiliateGetsPercent(affiliate, config);
    const next = Math.max(0, Math.min(maxYouKeep, 100 - affiliateGetsPercent));
    setYouKeep(next);
    setInitialYouKeep(next);
    setError("");
  }, [affiliate, config, maxYouKeep, open]);

  async function submit() {
    if (!affiliate?.account_id) {
      setError(t("affiliate.error.accountIdRequired"));
      return;
    }
    setSubmitting(true);
    setError("");
    try {
      await adminPost("/v1/referral/multi_level/admin/update/affiliate", {
        rebate_rate: bonusMaxRebatePercent / 100,
        account_ids: [affiliate.account_id],
      });
      toast({ title: t("affiliate.affiliateAllocationUpdated") });
      onSuccess();
      onClose();
    } catch (err) {
      setError(
        errorMessage(err, t("affiliate.error.updateAffiliateAllocation"))
      );
    } finally {
      setSubmitting(false);
    }
  }

  const isReducingAffiliateAllocation =
    Math.floor(youKeep) > Math.floor(initialYouKeep);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={t("affiliate.customizeAllocationFor", {
        address: formatShort(affiliate?.user_address),
      })}
      className="max-w-[560px]"
    >
      <div className="space-y-4">
        <div className="grid gap-2 rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 text-sm sm:grid-cols-2">
          <span className="text-(--fg-secondary)">
            {t("affiliate.affiliateAddress")}
          </span>
          <span className="text-right text-(--fg-primary)">
            <CopyableIdentifier
              value={affiliate?.user_address}
              label={t("affiliate.affiliateAddress")}
            />
          </span>
          <span className="text-(--fg-secondary)">
            {t("affiliate.referralCode")}
          </span>
          <span className="text-right font-mono text-(--fg-primary)">
            {affiliate?.referral_code || "--"}
          </span>
        </div>
        <AllocationRange
          value={youKeep}
          onChange={value => setYouKeep(Math.min(value, maxYouKeep))}
          directBonusPercent={baseRebatePercent}
        />
        {isReducingAffiliateAllocation && (
          <div className="rounded-xl border border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)] px-3 py-2 text-xs leading-5 text-[#D9AB52]">
            {t("affiliate.reductionImpactWarning")}
          </div>
        )}
        <ErrorBanner message={error} />
        <ConfirmFooter
          okText={t("common.save")}
          onCancel={onClose}
          onConfirm={submit}
          disabled={Math.floor(youKeep) === Math.floor(initialYouKeep)}
          loading={submitting}
        />
      </div>
    </Modal>
  );
}

function ResetAffiliateModal({
  open,
  affiliate,
  config,
  onClose,
  onSuccess,
}: {
  open: boolean;
  affiliate?: AffiliateRow;
  config: MLRConfig | null;
  onClose: () => void;
  onSuccess: () => void;
}) {
  const { t } = useTranslation();
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");
  const hasResetRate =
    config?.bonus_max_rebate_rate !== undefined ||
    config?.base_rebate_rate !== undefined;
  const affiliateGets =
    (config?.bonus_max_rebate_rate ?? 0) + (config?.base_rebate_rate ?? 0);
  const youKeep = Math.max(0, 1 - affiliateGets);
  const currentAffiliateGets =
    (affiliate?.max_rebate_rate ?? 0) +
    (affiliate?.direct_bonus_rebate_rate ?? 0);
  const showResetWarning =
    hasResetRate &&
    affiliate?.max_rebate_rate !== undefined &&
    affiliateGets < currentAffiliateGets;

  useEffect(() => {
    if (open) setError("");
  }, [open]);

  async function submit() {
    if (!affiliate?.account_id) {
      setError(t("affiliate.error.accountIdRequired"));
      return;
    }
    setSubmitting(true);
    setError("");
    try {
      await adminPost("/v1/referral/multi_level/admin/reset/affiliate", {
        account_ids: [affiliate.account_id],
      });
      toast({ title: t("affiliate.affiliateAllocationReset") });
      onSuccess();
      onClose();
    } catch (err) {
      setError(
        errorMessage(err, t("affiliate.error.resetAffiliateAllocation"))
      );
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={t("affiliate.resetAllocationFor", {
        address: formatShort(affiliate?.user_address),
      })}
      className="max-w-[560px]"
    >
      <div className="space-y-4">
        {showResetWarning && (
          <div className="rounded-xl border border-[rgba(217,171,82,0.28)] bg-[rgba(217,171,82,0.08)] px-3 py-2 text-xs leading-5 text-[#D9AB52]">
            {t("affiliate.resetOnlyHigherWarning")}
          </div>
        )}
        <div className="grid gap-2 rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-3 text-sm sm:grid-cols-2">
          <span className="text-(--fg-secondary)">
            {t("affiliate.affiliateAddress")}
          </span>
          <span className="text-right text-(--fg-primary)">
            <CopyableIdentifier
              value={affiliate?.user_address}
              label={t("affiliate.affiliateAddress")}
            />
          </span>
          <span className="text-(--fg-secondary)">
            {t("affiliate.referralCode")}
          </span>
          <span className="text-right font-mono text-(--fg-primary)">
            {affiliate?.referral_code || "--"}
          </span>
          <span className="text-(--fg-secondary)">
            {t("affiliate.youKeep")}
          </span>
          <span className="text-right text-[#00B59F]">
            {hasResetRate ? formatPercent(youKeep) : "--"}
          </span>
          <span className="text-(--fg-secondary)">
            {t("affiliate.affiliateGets")}
          </span>
          <span className="text-right text-(--fg-primary)">
            {hasResetRate ? formatPercent(affiliateGets) : "--"}
          </span>
        </div>
        <ErrorBanner message={error} />
        <ConfirmFooter
          okText={t("affiliate.reset")}
          onCancel={onClose}
          onConfirm={submit}
          loading={submitting}
        />
      </div>
    </Modal>
  );
}

function RefereeListModal({
  open,
  affiliate,
  config,
  onClose,
}: {
  open: boolean;
  affiliate?: AffiliateRow;
  config: MLRConfig | null;
  onClose: () => void;
}) {
  const { t } = useTranslation();
  const [rows, setRows] = useState<RefereeRow[]>([]);
  const [meta, setMeta] = useState<PageMeta>();
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(20);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const directBonusRate = getBaseReferralRate(config);

  useEffect(() => {
    if (!open || !affiliate?.user_address) return;
    let cancelled = false;
    setLoading(true);
    setError("");
    adminGet<unknown>("/v1/referral/multi_level/admin/referee_list", {
      page,
      size: pageSize,
      referrer_address: affiliate.user_address,
      sort_by: "code_binding_time",
      sort_order: "descending",
    })
      .then(payload => {
        if (cancelled) return;
        const result = extractPage<RefereeRow>(payload);
        setRows(result.rows);
        setMeta(result.meta);
      })
      .catch(err => {
        if (!cancelled) {
          setRows([]);
          setMeta(undefined);
          setError(errorMessage(err, t("affiliate.error.loadReferees")));
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => {
      cancelled = true;
    };
  }, [affiliate?.user_address, open, page, pageSize, t]);

  const total = getTotal(meta, rows.length);

  return (
    <Modal
      open={open}
      onClose={onClose}
      title={t("affiliate.refereesFor", {
        address: formatShort(affiliate?.user_address),
      })}
      className="max-w-[960px]"
    >
      <div className="space-y-4">
        <ErrorBanner message={error} />
        <DataTableShell>
          {loading ? (
            <InlineSpinner label={t("affiliate.loadingReferees")} />
          ) : rows.length === 0 ? (
            <div className="p-4">
              <EmptyState>{t("affiliate.noRefereesFound")}</EmptyState>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full min-w-[760px] text-left">
                <thead className="bg-(--bg-surface-secondary)">
                  <tr>
                    <TableHeaderCell>
                      {t("affiliate.refereeAddress")}
                    </TableHeaderCell>
                    <TableHeaderCell>
                      {t("affiliate.referredBy")}
                    </TableHeaderCell>
                    <TableHeaderCell>
                      {t("affiliate.bindingTime")}
                    </TableHeaderCell>
                    <TableHeaderCell>
                      {t("affiliate.refereeAllocation")}
                    </TableHeaderCell>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((row, index) => {
                    const refereeRate =
                      (row.referee_rebate_rate ?? 0) +
                      (row.bind_type === "legacy" ? 0 : directBonusRate);
                    return (
                      <tr
                        key={`${row.account_id || row.user_address || row.address}-${index}`}
                        className="border-t border-(--line-subtle)"
                      >
                        <TableCell>
                          <CopyableIdentifier
                            value={row.user_address || row.address}
                            label={t("affiliate.refereeAddress")}
                          />
                        </TableCell>
                        <TableCell>
                          <div className="space-y-1">
                            <CopyableIdentifier
                              value={row.referrer_address}
                              label={t("affiliate.referrerAddress")}
                            />
                            {row.bind_code && (
                              <div className="font-mono text-xs text-(--fg-secondary)">
                                {row.bind_code}
                                {row.bind_type === "legacy"
                                  ? ` (${t("affiliate.legacy")})`
                                  : ""}
                              </div>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          {formatDate(row.code_binding_time)}
                        </TableCell>
                        <TableCell>{formatPercent(refereeRate)}</TableCell>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
          <PaginationControls
            page={page}
            pageSize={pageSize}
            total={total}
            loading={loading}
            onPageChange={setPage}
            onPageSizeChange={size => {
              setPageSize(size);
              setPage(1);
            }}
          />
        </DataTableShell>
      </div>
    </Modal>
  );
}

